import "./popover.css";

import { Popover } from "radix-ui";

export type PopoverRootProps = React.ComponentProps<typeof Popover.Root>;

export const PopoverRoot = (props: PopoverRootProps) => {
  return <Popover.Root {...props} />;
};

import { Popover } from "radix-ui";

export type PopoverTriggerProps = React.ComponentProps<typeof Popover.Trigger>;

export const PopoverTrigger = (props: PopoverTriggerProps) => {
  return <Popover.Trigger asChild {...props} />;
};

import { X } from "lucide-react";
import { Popover } from "radix-ui";
import { cn } from "tailwind-variants";

import { popoverVariants } from "./popover.variants";

export type PopoverContentProps = React.ComponentProps<typeof Popover.Content>;

export const PopoverContent = ({
  children,
  className,
  sideOffset = 4,
  ...props
}: PopoverContentProps) => {
  const { close, content } = popoverVariants();

  return (
    <Popover.Portal>
      <Popover.Content className={cn(content(), className)} sideOffset={sideOffset} {...props}>
        {children}
        <Popover.Close aria-label="Close" className={close()}>
          <X />
        </Popover.Close>
      </Popover.Content>
    </Popover.Portal>
  );
};

import { tv, type VariantProps } from "tailwind-variants";

export const popoverVariants = tv({
  slots: {
    close: "popover__close",
    content: "popover__content",
  },
});

export type PopoverVariants = VariantProps<typeof popoverVariants>;

.popover__content {
  @apply bg-popover text-popover-foreground z-50 w-72 rounded-md border p-4 shadow-md outline-none;

  &[data-state="open"] {
    @apply animate-in fade-in-0 zoom-in-95;
  }

  &[data-state="closed"] {
    @apply animate-out fade-out-0 zoom-out-95;
  }

  &[data-side="bottom"] {
    @apply slide-in-from-top-2;
  }

  &[data-side="left"] {
    @apply slide-in-from-right-2;
  }

  &[data-side="right"] {
    @apply slide-in-from-left-2;
  }

  &[data-side="top"] {
    @apply slide-in-from-bottom-2;
  }
}

.popover__close {
  @apply absolute top-2 right-2 rounded-sm opacity-70 transition-opacity;

  &:hover {
    @apply opacity-100;
  }

  &:focus-visible {
    @apply outline-ring outline-2 outline-offset-2;
  }

  & svg {
    @apply size-4;
  }
}

import { PopoverContent } from "./popover-content";
import { PopoverRoot } from "./popover-root";
import { PopoverTrigger } from "./popover-trigger";

export const Popover = {
  Content: PopoverContent,
  Root: PopoverRoot,
  Trigger: PopoverTrigger,
};

export { PopoverContent, PopoverRoot, PopoverTrigger };

export { type PopoverVariants, popoverVariants } from "./popover.variants";
